5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteOptions {
13	  followUp?: boolean;
14	}
15	
16	export interface QuoteResult {
17	  basePremium: number;
18	  premium: number;
19	  items: Item[];
20	  remainingCap?: number;
21	}
22	
23	const basePremiumByType: Record<string, number> = {
24	  amulet: 60,
25	  sword: 100,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	const PROCESSING_FEE = 5;
33	const BLOCK_OF_THREE_PREMIUM = 60;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FIRST_INSURANCE_RATE = 0.1;
36	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
40	
41	function enchantmentLevel(item: Item): number {
42	  return item.enchantment ?? 0;
43	}
44	
45	function surchargeRateFor(item: Item): number {
46	  let rate = 0;
47	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
48	  if (enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
49	  return rate;
50	}
51	
52	function surchargeFor(item: Item): number {
53	  return basePremiumByType[item.type] * surchargeRateFor(item);
54	}
55	
56	function premiumForTypeBlock(type: string, count: number): number {
57	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
58	  return count * basePremiumByType[type];
59	}
60	
61	export function quote(
62	  customer: Customer,
63	  items: Item[],
64	  options: QuoteOptions = {},
65	): QuoteResult {
66	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
67	    counts[item.type] = (counts[item.type] ?? 0) + 1;
68	    return counts;
69	  }, {});
70	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
71	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
72	    0,
73	  );
74	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
75	  const basePremium = baseWithoutSurcharges + surcharges;
76	
77	  let premium = basePremium;
78	  if (customer.yearsWithMHPCO >= 2) premium -= baseWithoutSurcharges * LOYALTY_DISCOUNT_RATE;
79	  premium += baseWithoutSurcharges * FIRST_INSURANCE_RATE;
80	  if (options.followUp) premium -= baseWithoutSurcharges * FOLLOW_UP_DISCOUNT_RATE;
81	  premium = Math.ceil(premium + PROCESSING_FEE);
82	
83	  return { basePremium, premium, items };
84	}
85	
86	export interface Damage {
87	  itemType: string;
88	  amount: number;
89	}
90	
91	export interface Incident {
92	  cause: string;
93	  damages: Damage[];
94	}
95	
96	export interface ClaimResult {
97	  payout: number;
98	  remainingCap: number;
99	}
100	
101	const insuranceValueByType: Record<string, number> = {
102	  sword: 1000,
103	  amulet: 600,
104	  staff: 800,
105	  potion: 400,
106	  rune: 250,
107	  moonstone: 250,
108	};
109	
110	const CAP_MULTIPLIER = 2;
111	const DEDUCTIBLE = 100;
112	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
113	const HALF_REIMBURSEMENT_RATE = 0.5;
114	
115	function totalInsuranceValue(policy: QuoteResult): number {
116	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
117	}
118	
119	function remainingCapFor(policy: QuoteResult): number {
120	  return policy.remainingCap ?? CAP_MULTIPLIER * totalInsuranceValue(policy);
121	}
122	
123	function reimbursedAmount(damage: Damage, policy: QuoteResult): number {
124	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
125	  const halfReimbursementApplies =
126	    damagedItem !== undefined &&
127	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
128	  return halfReimbursementApplies
129	    ? damage.amount * HALF_REIMBURSEMENT_RATE
130	    : damage.amount;
131	}
132	
133	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
134	  return reimbursedAmount(damage, policy) - DEDUCTIBLE;
135	}
136	
137	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
138	  const totalPayout = incident.damages.reduce(
139	    (total, damage) => total + payoutForDamage(damage, policy),
140	    0,
141	  );
142	  const desiredPayout = Math.floor(totalPayout);
143	  const remainingCapBefore = remainingCapFor(policy);
144	  const payout = Math.min(desiredPayout, remainingCapBefore);
145	  const remainingCap = remainingCapBefore - payout;
146	  policy.remainingCap = remainingCap;
147	  return { payout, remainingCap };
148	}
